// Per-client lead scan target. Returns leads owned by BI-enabled clients,
// up to 200 oldest-touched leads per run (rate-limit safe). The 6h schedule
// means each lead gets re-scanned ~4×/day at most.
const clients = $input.first().json;
const clientList = Array.isArray(clients) ? clients : (clients && clients.id ? [clients] : []);
if (clientList.length === 0) {
  return [{ json: { _empty: true, reason: 'no_bi_enabled_clients' } }];
}
return clientList.map(function (c) {
  return { json: {
    client_id: c.id,
    client_name: c.client_name,
    niche_name: c.niche_name || c.vertical || 'service_industry',
    city: c.city || null
  } };
});

// Per-lead source scanner. V1 implements the cheap-source MVP:
//   - calendar: birthday match (if lead.birthday present)
//   - calendar: lead anniversary (account-creation milestone at 30/90/365d)
//   - business: company name change signal (placeholder — needs CRM diff)
//   - vertical_specific: niche-specific cheap probes
// Expensive sources (LinkedIn API, Apollo enrichment, news scraping) are
// declared as TODO Code nodes so Mary can wire them per-client when
// credentials are bound. This keeps the workflow runnable today against
// real data without external paid integrations.
const clientCtx = $('Per Client Batch').item.json;
const leadsRaw = $input.first().json;
const leads = Array.isArray(leadsRaw) ? leadsRaw : (leadsRaw && leadsRaw.id ? [leadsRaw] : []);
if (leads.length === 0) {
  return [{ json: { _empty: true, client_id: clientCtx.client_id } }];
}

const now = new Date();
const todayMonth = now.getUTCMonth() + 1;
const todayDay = now.getUTCDate();
const signals = [];

for (var i = 0; i < leads.length; i++) {
  var lead = leads[i];

  // -- calendar: birthday match (today ± 7 days) --
  if (lead.birthday) {
    try {
      var d = new Date(lead.birthday);
      if (!isNaN(d.getTime())) {
        var bm = d.getUTCMonth() + 1;
        var bd = d.getUTCDate();
        var dayDiff = Math.abs(bm - todayMonth) * 30 + Math.abs(bd - todayDay);
        if (dayDiff <= 7) {
          signals.push({
            lead_id: lead.id,
            client_id: clientCtx.client_id,
            signal_type: 'birthday_window_7d',
            signal_category: 'calendar',
            niche_name: clientCtx.niche_name,
            signal_data: { birthday: lead.birthday, days_until_or_since: dayDiff, lead_first_name: lead.first_name || (lead.full_name || '').split(' ')[0] || null },
            signal_source: 'public',
            sensitivity_level: 'low'
          });
        }
      }
    } catch (e) { /* skip malformed dates */ }
  }

  // -- calendar: account anniversary (30 / 90 / 365 days) --
  if (lead.date_created) {
    try {
      var created = new Date(lead.date_created);
      var ageDays = Math.floor((now.getTime() - created.getTime()) / 86400000);
      [30, 90, 365].forEach(function (window) {
        if (Math.abs(ageDays - window) <= 1) {
          signals.push({
            lead_id: lead.id,
            client_id: clientCtx.client_id,
            signal_type: 'lead_anniversary_' + window + 'd',
            signal_category: 'calendar',
            niche_name: clientCtx.niche_name,
            signal_data: { age_days: ageDays, milestone: window },
            signal_source: 'public',
            sensitivity_level: 'low'
          });
        }
      });
    } catch (e) { /* skip */ }
  }

  // -- vertical_specific (insurance): policy_renewal_due placeholder --
  // Real implementation: read policies table renewal_date once schema lands.
  // Insurance Phase 4 will populate. V1 emits a nudge if niche==insurance and lead has been quiet 60d+.
  if (clientCtx.niche_name === 'insurance' || clientCtx.niche_name === 'insurance_broker') {
    // placeholder — requires policies table (Phase 4)
  }

  // -- TODO sources (placeholder Code nodes, wire when credentials available) --
  // - LinkedIn: job changes / promotions / company news / posts (Unipile API per client)
  // - Apollo: business expansion / employee count delta
  // - News: per-lead news mentions (NewsAPI org search)
  // - Public records: address changes / business filings (per-vertical APIs)
}

if (signals.length === 0) {
  return [{ json: { _empty: true, client_id: clientCtx.client_id, reason: 'no_signals_found' } }];
}
return signals.map(function (s) { return { json: s }; });

// Run summary. Aggregates per-source counts + total signals inserted.
const all = $('Scan Sources Per Lead').all();
let total = 0;
let emptyClients = 0;
const byCategory = {};
for (const it of all) {
  if (it.json._empty) { emptyClients += 1; continue; }
  total += 1;
  const cat = it.json.signal_category || 'unknown';
  byCategory[cat] = (byCategory[cat] || 0) + 1;
}
return { json: {
  total_signals_scanned: total,
  empty_client_runs: emptyClients,
  signals_by_category: byCategory,
  run_at: new Date().toISOString()
} };
